@page "/category/{CategoryName}"
@using RecipeSharingCommunity.Models
@using RecipeSharingCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a> &rsaquo; <span>@CategoryName</span>
</nav>

<h1>@GetCategoryIcon(CategoryName) @CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="recipe-grid">
        @foreach (var recipe in recipes)
        {
            <a class="recipe-card" href="/recipe/@recipe.Id">
                <h3>@recipe.Title</h3>
                <p>@recipe.Description</p>
                <div class="recipe-meta">
                    <span class="stars-display">
                        @for (int i = 1; i <= 5; i++)
                        {
                            <span class="@(i <= Math.Round(recipe.AverageRating) ? "star filled" : "star")">★</span>
                        }
                    </span>
                    <span>@recipe.AverageRating / 5</span>
                    <span>(@recipe.Ratings.Count ratings)</span>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥢",
        "Desserts" => "🍪",
        _ => "🍴"
    };
}

@page "/recipe/{RecipeId:int}"
@using RecipeSharingCommunity.Models
@using RecipeSharingCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe Not Found")</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="/">Back to Home</a>
}
else
{
    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo;
        <a href="/category/@recipe.Category">@recipe.Category</a> &rsaquo;
        <span>@recipe.Title</span>
    </nav>

    <article class="recipe-detail">
        <h1>@recipe.Title</h1>
        <p class="recipe-description">@recipe.Description</p>

        <section class="recipe-section">
            <h2>Ingredients</h2>
            <ul class="ingredients-list">
                @foreach (var ingredient in recipe.Ingredients)
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section class="recipe-section">
            <h2>Steps</h2>
            <ol class="steps-list">
                @foreach (var step in recipe.Steps)
                {
                    <li>@step</li>
                }
            </ol>
        </section>

        <section class="recipe-section">
            <StarRating RecipeId="recipe.Id" />
        </section>
    </article>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer

@using RecipeSharingCommunity.Services

@inject RecipeService RecipeService

<div class="star-rating-widget">
    <h3>Rate This Recipe</h3>
    <div class="rating-stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="star-btn @(star <= (hoverRating ?? selectedRating) ? "active" : "")"
                    @onclick="() => SubmitRating(star)"
                    @onmouseover="() => hoverRating = star"
                    @onmouseout="() => hoverRating = null"
                    aria-label="Rate @star stars">
                ★
            </button>
        }
    </div>
    @if (selectedRating > 0)
    {
        <p class="rating-feedback">You rated this recipe @selectedRating out of 5 stars!</p>
    }
    <p class="rating-summary">
        Average: @recipe?.AverageRating / 5 (@recipe?.Ratings.Count ratings)
    </p>
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private Models.Recipe? recipe;
    private int selectedRating;
    private int? hoverRating;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        recipe = RecipeService.GetById(RecipeId);
    }
}

@page "/submit"
@rendermode InteractiveServer

@using RecipeSharingCommunity.Models
@using RecipeSharingCommunity.Services

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a> &rsaquo; <span>Submit Recipe</span>
</nav>

<h1>📝 Submit Your Recipe</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>🎉 Recipe Submitted!</h2>
        <p>Your recipe "<strong>@model.Title</strong>" has been added to the <strong>@model.Category</strong> category.</p>
        <a href="/recipe/@submittedId">View Your Recipe</a>
        <span> | </span>
        <a href="/submit">Submit Another</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-input" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-input">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Asian">Asian</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="form-group">
            <label for="description">Short Description</label>
            <InputTextArea id="description" @bind-Value="model.Description" class="form-input" rows="2"
                           placeholder="A brief description of your recipe" />
            <ValidationMessage For="() => model.Description" />
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="ingredientsText" class="form-input" rows="6"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="stepsText" class="form-input" rows="6"
                           placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
        </div>

        <button type="submit" class="btn-submit">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private string ingredientsText = string.Empty;
    private string stepsText = string.Empty;
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = model.Description,
            Ingredients = ingredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = stepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please provide a short description.")]
        public string Description { get; set; } = string.Empty;
    }
}

