    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    line-height: 1.6;
    color: #333;
    background: #fafafa;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

a { color: #d35400; text-decoration: none; }
a:hover { text-decoration: underline; }

h1:focus { outline: none; }

/* === Header === */
.site-header {
    background: #2c3e50;
    color: white;
    padding: 0 1.5rem;
}

.site-header nav {
    max-width: 960px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 60px;
}

.site-header .brand {
    font-size: 1.4rem;
    font-weight: 700;
    color: white;
}

.site-header .brand:hover { text-decoration: none; }

.nav-links a {
    color: #ecf0f1;
    margin-left: 1.5rem;
    font-weight: 500;
}

.nav-links a:hover { color: #f39c12; text-decoration: none; }

/* === Container === */
.container {
    max-width: 960px;
    margin: 0 auto;
    padding: 2rem 1.5rem;
    flex: 1;
}

/* === Footer === */
.site-footer {
    background: #2c3e50;
    color: #bdc3c7;
    text-align: center;
    padding: 1rem;
    font-size: 0.9rem;
}

/* === Hero === */
.hero {
    text-align: center;
    padding: 2.5rem 1rem;
    background: linear-gradient(135deg, #f39c12, #e74c3c);
    color: white;
    border-radius: 12px;
    margin-bottom: 2rem;
}

.hero h1 { font-size: 2.2rem; margin-bottom: 0.5rem; }
.hero p { font-size: 1.1rem; opacity: 0.95; }

/* === Breadcrumb === */
.breadcrumb {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
    color: #7f8c8d;
}

.breadcrumb a { color: #d35400; }

/* === Category Grid === */
.category-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 1rem;
    margin-bottom: 2rem;
}

.category-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 1.5rem 1rem;
    background: white;
    border-radius: 10px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.08);
    transition: transform 0.2s, box-shadow 0.2s;
    color: #333;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 6px 20px rgba(0,0,0,0.12);
    text-decoration: none;
}

.category-icon { font-size: 2.5rem; margin-bottom: 0.5rem; }
.category-name { font-size: 1.2rem; font-weight: 600; }
.category-count { font-size: 0.85rem; color: #7f8c8d; margin-top: 0.25rem; }

/* === Recipe Grid === */
.recipe-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.25rem;
}

.recipe-card {
    background: white;
    border-radius: 10px;
    padding: 1.5rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.08);
    transition: transform 0.2s, box-shadow 0.2s;
    color: #333;
}

.recipe-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 6px 20px rgba(0,0,0,0.12);
    text-decoration: none;
}

.recipe-card h3 { margin-bottom: 0.5rem; color: #2c3e50; }
.recipe-card p { font-size: 0.9rem; color: #666; margin-bottom: 0.75rem; }

.recipe-meta {
    font-size: 0.85rem;
    color: #7f8c8d;
    display: flex;
    align-items: center;
    gap: 0.4rem;
}

/* === Stars === */
.star { color: #ddd; font-size: 1rem; }
.star.filled { color: #f39c12; }

/* === Recipe Detail === */
.recipe-detail h1 { margin-bottom: 0.5rem; }
.recipe-description { font-size: 1.1rem; color: #555; margin-bottom: 1.5rem; }

.recipe-section {
    margin-bottom: 2rem;
}

.recipe-section h2 {
    font-size: 1.3rem;
    color: #2c3e50;
    border-bottom: 2px solid #f39c12;
    padding-bottom: 0.3rem;
    margin-bottom: 1rem;
}

.ingredients-list { list-style: disc; padding-left: 1.5rem; }
.ingredients-list li { padding: 0.25rem 0; }
.steps-list { padding-left: 1.5rem; }
.steps-list li { padding: 0.4rem 0; }

/* === Star Rating Widget === */
.star-rating-widget {
    background: #fff8f0;
    border: 1px solid #f0e0cc;
    border-radius: 10px;
    padding: 1.5rem;
    text-align: center;
}

.star-rating-widget h3 { margin-bottom: 0.75rem; color: #2c3e50; }

.rating-stars { display: flex; justify-content: center; gap: 0.25rem; margin-bottom: 0.75rem; }

.star-btn {
    background: none;
    border: none;
    font-size: 2rem;
    color: #ddd;
    cursor: pointer;
    transition: color 0.15s, transform 0.15s;
    padding: 0;
    line-height: 1;
}

.star-btn:hover { transform: scale(1.2); }
.star-btn.active { color: #f39c12; }

.rating-feedback { color: #27ae60; font-weight: 600; margin-bottom: 0.5rem; }
.rating-summary { color: #7f8c8d; font-size: 0.9rem; }

/* === CTA === */
.cta-section {
    text-align: center;
    padding: 2rem;
    background: #ecf0f1;
    border-radius: 10px;
}

.cta-section h3 { margin-bottom: 1rem; color: #2c3e50; }

/* === Forms === */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.3rem;
    color: #2c3e50;
}

.form-input {
    width: 100%;
    padding: 0.6rem 0.8rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 1rem;
    font-family: inherit;
    transition: border-color 0.2s;
}

.form-input:focus {
    outline: none;
    border-color: #f39c12;
    box-shadow: 0 0 0 3px rgba(243, 156, 18, 0.15);
}

textarea.form-input { resize: vertical; }

.btn-submit {
    display: inline-block;
    background: #e67e22;
    color: white;
    padding: 0.75rem 2rem;
    border: none;
    border-radius: 8px;
    font-size: 1.05rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
    text-decoration: none;
}

.btn-submit:hover { background: #d35400; text-decoration: none; }

.success-message {
    background: #eafaf1;
    border: 1px solid #a3d9a5;
    border-radius: 10px;
    padding: 2rem;
    text-align: center;
}

.success-message h2 { color: #27ae60; margin-bottom: 0.5rem; }
.success-message a { color: #d35400; font-weight: 600; }

/* === Validation === */
.valid.modified:not([type=checkbox]) { outline: 1px solid #26b050; }
.invalid { outline: 1px solid #e50000; }
.validation-message { color: #e50000; font-size: 0.85rem; margin-top: 0.25rem; }

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
